/**
 * Composable for the `AArrowDown` icon.
 *
 * For more information see the official icon documentation: https://lucide.dev/icons/a-arrow-down
 *
 * @param modifier The `Modifier` to be applied to the icon.
 * @param color The `Color` of the icon.
 * @param contentDescription The description of the icon for accessibility.
 * @since 1.0.0
 */
@Composable
public fun AArrowDown(
  modifier: Modifier = Modifier,
  color: Color = Color.Black,
  contentDescription: String? = null,
) {
  Icon(
    painter = LucidePainter.aArrowDown(),
    contentDescription = contentDescription,
    modifier = modifier,
    tint = color,
  )
}

